import "../Stylesheets/Menu.css";

export default function Menu() {
  return (
    <nav className="w-full h-24 py-5 inline-flex justify-between items-center shadow-2xl">
      <a
        className="inline-flex text-4xl font-sans font-bold bg-yellow-300 h-fit ml-[5%]"
        href="#"
      >
        Corrida dos DEVs
        <img src="logo.svg" alt="Corrida-dos-devs-logo" />
      </a>
      <ul className="nav-list">
        <li>Ranking</li>
        <li>Registro</li>
        <li>Login</li>
      </ul>
    </nav>
  );
}
